// mm/src/steps/completeOrderStep.js
import React, { useEffect, useMemo, useState } from 'react';
import { useWorkflow } from '../store/workflowContext';

import PackageSelector from '../components/packageSelector.js';
import OrderSummary from '../components/orderSummary.js';
import PaymentDelivery from '../components/paymentDelivery.js';

import { isSignedIn, getUserEmail } from '../utils/auth';
import { getPendingCheckout, clearPendingCheckout } from '../utils/pendingCheckout';
import { loadWorkflowFiles, clearWorkflowFiles } from '../utils/fileStore';
import { uploadDocuments } from '../api/uploadDocuments';
import { createCheckoutSession } from '../api/checkout';

const PACKAGE_PRICES = {
  basic: 49,
  standard: 99,
  premium: 199,
};

function getOriginSafe() {
  if (typeof window === 'undefined') return '';
  return window.location.origin || '';
}

function isValidEmail(email) {
  const v = String(email || '').trim();
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(v);
}

export default function CompleteOrderStep() {
  const { bookDetails, details, design, order, setOrder } = useWorkflow();

  const signedIn = isSignedIn();
  const bookTitle = bookDetails?.title || '';
  const pkgId = order?.packageId || 'standard';
  const total = PACKAGE_PRICES[pkgId] ?? 0;

  const [busy, setBusy] = useState(false);
  const [busyLabel, setBusyLabel] = useState('');
  const [error, setError] = useState('');

  // Autofill email if signed in and empty
  useEffect(() => {
    if (!signedIn) return;
    if ((order?.deliveryEmail || '').trim()) return;

    const em = getUserEmail();
    if (em) setOrder((p) => ({ ...p, deliveryEmail: em }));
  }, [signedIn, order?.deliveryEmail, setOrder]);

  const checkoutPayload = useMemo(() => {
    return () => ({
      bookTitle: bookDetails?.title || '',
      authorName: bookDetails?.author || '',

      author: {
        prefix: details?.prefix || '',
        firstName: details?.firstName || '',
        middleName: details?.middleName || '',
        lastName: details?.lastName || '',
        suffix: details?.suffix || '',
      },

      targetAudience: {
        ageRanges: details?.ageRanges || [],
        demographics: details?.demographics || [],
      },

      publishing: {
        distributionChannels: details?.distributionChannels || [],
        publishingTimeline: details?.publishingTimeline || '',
        authorExperienceLevel: details?.authorExperienceLevel || '',
      },

      additional: {
        marketPositioning: details?.marketPositioning || '',
        seriesInformation: details?.seriesInformation || '',
        brandingPreferences: details?.brandingPreferences || '',
        marketingObjectives: details?.marketingObjectives || '',
      },

      design: {
        typography: design?.typography || '',
        layout: design?.layout || '',
        trim: design?.trim || '',
      },
    });
  }, [bookDetails, details, design]);

  const isPaid = order?.paymentStatus === 'paid';

  // Upload local workflow files to backend (auth required)
  const uploadStoredFilesToBackend = async () => {
    const files = await loadWorkflowFiles(); // [{id,file,name,tag...}]
    if (!files || files.length === 0) {
      throw new Error('No stored files found to upload.');
    }

    // Upload sequentially (safe + simple)
    for (let i = 0; i < files.length; i++) {
      const item = files[i];
      if (!item?.file) continue;
      setBusyLabel(`Uploading documents (${i + 1}/${files.length})…`);
      await uploadDocuments(item.file);
    }
  };

  // Create checkout session and redirect
  const startCheckoutRedirect = async ({ packageId, amount, deliveryEmail, payload }) => {
    const origin = getOriginSafe();
    if (!origin) throw new Error('Unable to determine site origin.');

    setBusyLabel('Preparing checkout…');

    const resp = await createCheckoutSession({
      ...(payload || {}),
      packageId,
      amount,
      deliveryEmail,
      successUrl: `${origin}/workflow/payment/success`,
      cancelUrl: `${origin}/workflow/order`,
    });

    const checkoutUrl = resp?.data?.checkoutUrl;
    if (!checkoutUrl) throw new Error('Checkout failed: backend did not return checkoutUrl.');

    window.location.assign(checkoutUrl);
  };

  // ✅ Resume flow after register/login:
  // - pending checkout exists
  // - user is now signed in
  // - upload stored files to backend
  // - create checkout session and redirect
  useEffect(() => {
    const run = async () => {
      if (!signedIn) return;

      const pending = getPendingCheckout();
      if (!pending) return;

      setBusy(true);
      setError('');
      setBusyLabel('Resuming checkout…');

      try {
        // Ensure UI email matches pending
        if (pending.deliveryEmail && pending.deliveryEmail !== order?.deliveryEmail) {
          setOrder((p) => ({ ...p, deliveryEmail: pending.deliveryEmail }));
        }

        await uploadStoredFilesToBackend();

        // Optional: clear local files once uploaded
        await clearWorkflowFiles();

        // Clear pending BEFORE redirect (so refresh doesn't re-trigger)
        clearPendingCheckout();

        await startCheckoutRedirect({
          packageId: pending.packageId,
          amount: pending.amount,
          deliveryEmail: pending.deliveryEmail,
          payload: pending.payload,
        });
      } catch (e) {
        console.error(e);
        setError(e?.message || 'Could not resume checkout.');
      } finally {
        setBusy(false);
        setBusyLabel('');
      }
    };

    run();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [signedIn]);

  // ✅ Logged-in users: also upload before checkout.
  // This is called by PaymentDelivery via checkoutPayload (it only uses it to build payload),
  // so we expose an explicit handler below and pass it down as a prop.
  const onPayLoggedIn = async () => {
    setError('');

    const deliveryEmail = String(order?.deliveryEmail || '').trim();
    const amount = PACKAGE_PRICES[pkgId] ?? 0;

    if (!signedIn) {
      setError('You must be signed in to pay.');
      return;
    }
    if (!isValidEmail(deliveryEmail)) {
      setError('Please enter a valid email address for delivery.');
      return;
    }
    if (!pkgId) {
      setError('Please select a package to continue.');
      return;
    }
    if (!(amount > 0)) {
      setError('Invalid package amount. Please re-select your package.');
      return;
    }

    setBusy(true);
    setBusyLabel('Uploading documents…');

    try {
      // 1) Upload local workflow files
      await uploadStoredFilesToBackend();

      // Optional: clear local files once uploaded
      await clearWorkflowFiles();

      // 2) Create checkout + redirect
      const payload = typeof checkoutPayload === 'function' ? checkoutPayload() : {};
      await startCheckoutRedirect({
        packageId: pkgId,
        amount,
        deliveryEmail,
        payload,
      });
    } catch (e) {
      console.error(e);
      setError(e?.message || 'Could not start checkout.');
    } finally {
      setBusy(false);
      setBusyLabel('');
    }
  };

  // ---------- PAID VIEW (downloads) ----------
  if (isPaid) {
    return (
      <div className="text-center bg-white border border-slate-200 rounded-xl p-8">
        <h2 className="text-2xl font-semibold text-slate-900 mb-2">Order Complete ✅</h2>
        <p className="text-slate-600">Thanks! Your payment was received. Download your formatted files below.</p>

        <div className="mt-8 grid grid-cols-1 md:grid-cols-2 gap-4 text-left">
          <div className="border rounded-lg p-5">
            <div className="font-semibold text-slate-900">Print-ready PDF</div>
            <div className="text-sm text-slate-600 mt-1">Trim size + margins + typography applied</div>
            <button type="button" className="mt-4 px-4 py-2 rounded-md bg-blue-600 text-white hover:bg-blue-700">
              Download PDF
            </button>
          </div>

          <div className="border rounded-lg p-5">
            <div className="font-semibold text-slate-900">eBook Package</div>
            <div className="text-sm text-slate-600 mt-1">EPUB + cover assets</div>
            <button type="button" className="mt-4 px-4 py-2 rounded-md bg-blue-600 text-white hover:bg-blue-700">
              Download EPUB
            </button>
          </div>
        </div>

        <div className="mt-8 text-xs text-slate-500">
          Package: <span className="font-semibold">{pkgId}</span> • Total Paid:{' '}
          <span className="font-semibold">${total}</span>
        </div>
      </div>
    );
  }

  // ---------- NOT PAID VIEW (order/payment) ----------
  return (
    <div className="space-y-6">
      {/* Busy banner (resume or logged-in pre-upload) */}
      {busy ? (
        <div className="border rounded-xl p-6 bg-white">
          <div className="text-slate-900 font-semibold">{busyLabel || 'Working…'}</div>
          <div className="text-slate-600 text-sm mt-1">
            Please don’t close this tab.
          </div>
          <div className="mt-4 h-2 w-full bg-slate-100 rounded-full overflow-hidden">
            <div className="h-2 w-1/2 bg-blue-600 animate-pulse" />
          </div>
        </div>
      ) : null}

      {error ? (
        <div className="border border-red-200 bg-red-50 rounded-xl p-4 text-sm text-red-700">
          {error}
        </div>
      ) : null}

      <div className="border rounded-xl p-6 bg-white">
        <PackageSelector
          value={pkgId}
          onChange={(nextId) => setOrder((prev) => ({ ...prev, packageId: nextId }))}
        />
      </div>

      <OrderSummary
        bookTitle={bookTitle}
        details={details}
        design={design}
        packageId={pkgId}
        packagePrices={PACKAGE_PRICES}
      />

      {/* NOTE:
         PaymentDelivery must be the refactored version that:
         - If logged out: stores pending checkout and redirects to /register?returnTo=/workflow/order
         - If logged in: calls this onPayLoggedIn handler OR can accept a prop for that.

         We pass onPayLoggedIn here as an optional prop.
         If your PaymentDelivery doesn't accept it yet, add:
           export default function PaymentDelivery({... , onPayLoggedIn })
         and call it in the signed-in flow instead of createCheckoutSession directly.
      */}
      <PaymentDelivery
        packageId={pkgId}
        packagePrices={PACKAGE_PRICES}
        email={order?.deliveryEmail || ''}
        onEmailChange={(val) => setOrder((prev) => ({ ...prev, deliveryEmail: val }))}
        checkoutPayload={checkoutPayload}
        onPayLoggedIn={onPayLoggedIn}
        busy={busy}
      />

      <div className="text-xs text-slate-500 text-center">
        Total shown: <span className="font-semibold">${total}</span>
      </div>
    </div>
  );
}
